// NORMALIZADOR INPUT V17
let body = $input.item.json.body || {};
let data = body.data || {};
let msg = data.message || {};

let userMessage = "";
if (msg.extendedTextMessage && msg.extendedTextMessage.text) {
    userMessage = msg.extendedTextMessage.text;
}
else if (msg.conversation) {
    userMessage = msg.conversation;
}
else if (msg.conversationMessage && msg.conversationMessage.message) {
    userMessage = msg.conversationMessage.message;
}
else if (body.message) {
    userMessage = body.message;
}

if (!userMessage) userMessage = "Hola";

return {
  json: {
    ...$input.item.json,
    user_message: userMessage
  }
};

// FILTRO STEFAN V17 BULLETPROOF (V3)
// Este código evita que el workflow se rompa si faltan referencias

const inputObj = $input.item.json;
const inputData = inputObj.text || inputObj.output || inputObj.response || "";

// 1. PARSEO DE IA
let parsed = {};
if (typeof inputData === 'string' && inputData.trim() !== "") {
  const clean = inputData.replace(/```json/g, "").replace(/```/g, "").trim();
  try { 
    parsed = JSON.parse(clean); 
  } catch(e) {
    parsed = { respuesta_voz: clean, accion: 'info' }; 
  }
} else if (typeof inputData === 'object' && inputData !== null) {
  parsed = inputData;
}

// 2. SEGURIDAD DE SALIDA (Evita error 3 INVALID_ARGUMENT en TTS)
const voiceText = parsed.respuesta_voz || parsed.text || "Entendido.";
const lang = parsed.idioma || "de";
const accion = parsed.accion || "info";

// 3. IDENTIFICADOR DE USUARIO (WhatsApp/Web)
let remoteJid = "Web-User";

// Verificamos si existe el nodo Webhook de forma segura
try {
  const webhookNode = $("Webhook");
  if (webhookNode && webhookNode.item) {
    const body = webhookNode.item.json.body || {};
    remoteJid = body.data?.key?.remoteJid || body.remote_jid || "Web-User";
  }
} catch (e) {
  // Si el nodo no existe o no ha corrido, usamos el dato local o fallback
  remoteJid = inputObj.remote_jid || "Web-User";
}

return {
  json: {
    voice_text: voiceText,
    display_text: parsed.mensaje_texto || null,
    lang: lang,
    accion: accion,
    remote_jid: remoteJid
  }
};
